 1	import { type FormEvent, useState } from 'react';
 2	
 3	import { DatePicker, InputGroup, ToolbarFilter } from '@patternfly/react-core';
 4	
 5	import { changeFormatToISODate, isValidDate, parseISOtoJSDate, toISODate } from '../utils/dates';
 6	
 7	import type { FilterTypeProps } from './types';
 8	
 9	/**
10	 * This Filter type enables selecting a single date (a day).
11	 *
12	 * **FilterTypeProps are interpreted as follows**:<br>
13	 * 1) selectedFilters - dates in YYYY-MM-DD format (ISO date format).<br>
14	 * 2) onFilterUpdate - accepts the list of dates.<br>
15	 *
16	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
17	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/Filter/DateFilter.tsx)
18	 */
19	export const DateFilter = ({
20	  filterId,
21	  onFilterUpdate,
22	  placeholderLabel,
23	  selectedFilters = [],
24	  showFilter = true,
25	  title,
26	}: FilterTypeProps) => {
27	  const isString = (value: string | undefined): value is string => value !== undefined;
28	  const validFilters = selectedFilters?.map(changeFormatToISODate)?.filter(isString) ?? [];
29	
30	  // internal state - stored as ISO date string (no time)
31	  const [date, setDate] = useState();
32	
33	  const clearSingleDate = (option: string) => {
34	    onFilterUpdate([...validFilters.filter((filter) => filter !== option)]);
35	  };
36	
37	  const onDateChange: (event: FormEvent<HTMLInputElement>, value: string, date?: Date) => void = (
38	    _event,
39	    value,
40	  ) => {
41	    // require full format "YYYY-MM-DD" although partial date is also accepted
42	    // i.e. YYYY-MM gets parsed as YYYY-MM-01 and results in auto completing the date
43	    // unfortunately due to auto-complete user cannot delete the date char after char
44	    if (value?.length === 10 && isValidDate(value)) {
45	      const targetDate = changeFormatToISODate(value);
46	      setDate(targetDate);
47	      if (targetDate) {
48	        onFilterUpdate([...validFilters.filter((filter) => filter !== targetDate), targetDate]);
49	      }
50	    }
51	  };
52	
53	  return (
54	    <ToolbarFilter
55	      key={filterId}
56	      labels={validFilters}
57	      deleteLabel={(_category, option) => {
58	        clearSingleDate(option as string);
59	      }}
60	      deleteLabelGroup={() => onFilterUpdate([])}
61	      categoryName={title ?? ''}
62	      showToolbarItem={showFilter}
63	    >
64	      <InputGroup>
65	        <DatePicker
66	          value={date}
67	          dateFormat={toISODate}
68	          dateParse={parseISOtoJSDate}
69	          onChange={onDateChange}
70	          aria-label={title}
71	          placeholder={placeholderLabel}
72	          invalidFormatText={placeholderLabel}
73	          // default value ("parent") creates collision with sticky table header
74	          appendTo={document.body}
75	        />
76	      </InputGroup>
77	    </ToolbarFilter>
78	  );
79	};

